sql:
SELECT reward_name
FROM card_rewards
WHERE reward_type = 'card';

SELECT mean_model_score_change
FROM card_analytics
WHERE card_id = 1;

external_knowledge:
- "battle-tested" refers to cards that have been played more than 10 times; 
- "top-performing" means the card with the highest win rate; 
- "entered the fray" means the number of games played.

sql:
SELECT win_rate
FROM card_analytics
WHERE game_format = 'constructed' AND win_rate BETWEEN 0.4 AND 0.6;

SELECT game_format, AVG(win_rate) AS average_win_rate
FROM card_analytics
GROUP BY game_format;

SELECT AVG(win_rate) AS avg_win_rate
FROM card_analytics
WHERE game_format = 'constructed';

SELECT reward_type, SUM(frequency) AS total_frequency, COUNT(DISTINCT card_id) AS distinct_cards
FROM card_rewards
GROUP BY reward_type;

SELECT reward_name, frequency
FROM card_rewards
WHERE reward_id = 0;

SELECT reward_type, SUM(frequency) AS total_frequency
FROM card_rewards
GROUP BY reward_type;
